#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <iomanip>
#include <algorithm>

class Shape {
public:
    virtual ~Shape() = default;
    virtual double calculateArea() const {
        return 0;
    }
};

class Rectangle : public Shape {
private:
    double m_width;
    double m_height;

public:
    Rectangle(double width, double height)
        : m_width(std::max(0.0, width)), m_height(std::max(0.0, height)) {}

    double calculateArea() const override {
        return m_width * m_height;
    }
};

class Circle : public Shape {
private:
    double m_radius;

public:
    Circle(double radius)
        : m_radius(std::max(0.0, radius)) {}

    double calculateArea() const override {
        return M_PI * m_radius * m_radius;
    }
};

int main() {
    std::stringstream ss;
    ss << std::fixed << std::setprecision(2);

    Shape* rect1 = new Rectangle(5, 10);
    Shape* circ1 = new Circle(3);
    Shape* rect_neg_dim = new Rectangle(-2, 5); // Test with negative dimension, should become 0
    Shape* circ2 = new Circle(1.5);
    Shape* rect_zero_dim = new Rectangle(0, 10); // Test with zero dimension

    ss << "Rectangle (5x10) Area: " << rect1->calculateArea() << std::endl;
    ss << "Circle (radius 3) Area: " << circ1->calculateArea() << std::endl;
    ss << "Rectangle (-2x5) Area: " << rect_neg_dim->calculateArea() << std::endl;
    ss << "Circle (radius 1.5) Area: " << circ2->calculateArea() << std::endl;
    ss << "Rectangle (0x10) Area: " << rect_zero_dim->calculateArea() << std::endl;

    delete rect1;
    delete circ1;
    delete rect_neg_dim;
    delete circ2;
    delete rect_zero_dim;

    std::cout << ss.str();
    return 0;
}
